import{_ as e,c as i,o as s,a1 as a}from"./chunks/framework.DILC4Csi.js";const h=JSON.parse('{"title":"Superpowers Best Practices: Avoid AI Agent Pitfalls","description":"Master Superpowers best practices to prevent AI agents from cutting corners and rationalizing. Learn TDD, systematic debugging, evidence-first principles, and identify 12 common rationalization patterns.","frontmatter":{"title":"Superpowers Best Practices: Avoid AI Agent Pitfalls","sidebarTitle":"Pitfall Avoidance Guide","subtitle":"Best Practices & Pitfall Avoidance: Use Skills Correctly, Avoid Common Traps","description":"Master Superpowers best practices to prevent AI agents from cutting corners and rationalizing. Learn TDD, systematic debugging, evidence-first principles, and identify 12 common rationalization patterns.","tags":["best practices","pitfall avoidance","TDD","debugging"],"prerequisite":["start-using-skills"],"order":250},"headers":[],"relativePath":"obra/superpowers/faq/best-practices/index.md","filePath":"obra/superpowers/faq/best-practices/index.md"}'),o={name:"obra/superpowers/faq/best-practices/index.md"};function r(n,t,l,d,u,c){return s(),i("div",null,[...t[0]||(t[0]=[a(`<h1 id="best-practices-pitfall-avoidance-use-skills-correctly-avoid-common-traps" tabindex="-1">Best Practices &amp; Pitfall Avoidance: Use Skills Correctly, Avoid Common Traps <a class="header-anchor" href="#best-practices-pitfall-avoidance-use-skills-correctly-avoid-common-traps" aria-label="Permalink to &quot;Best Practices &amp; Pitfall Avoidance: Use Skills Correctly, Avoid Common Traps&quot;">​</a></h1><h2 id="what-you-ll-learn" tabindex="-1">What You&#39;ll Learn <a class="header-anchor" href="#what-you-ll-learn" aria-label="Permalink to &quot;What You&#39;ll Learn&quot;">​</a></h2><ul><li>Immediately recognize AI agent rationalization excuses and prevent lazy behaviors</li><li>Master core iron laws: TDD, systematic debugging, evidence-first</li><li>Avoid common anti-patterns and reduce rework and debugging time</li><li>Build efficient collaboration habits and establish quality consensus with AI agents</li></ul><h2 id="your-current-situation" tabindex="-1">Your Current Situation <a class="header-anchor" href="#your-current-situation" aria-label="Permalink to &quot;Your Current Situation&quot;">​</a></h2><p>You&#39;ve spent hours developing with an AI agent, only to discover:</p><ul><li>Code has no tests, features are full of bugs</li><li>AI says &quot;it should work,&quot; but it errors immediately when run</li><li>Fixed the same issue three times, each time introducing new bugs</li><li>AI convinced you to skip skills, saying &quot;this one is simple&quot;</li><li>During code review, you realize you implemented the wrong functionality</li></ul><p><strong>This isn&#39;t because AI isn&#39;t smart enough—it&#39;s because you let the AI &quot;cut corners.&quot;</strong></p><h2 id="superpowers-five-iron-laws" tabindex="-1">Superpowers&#39; Five Iron Laws <a class="header-anchor" href="#superpowers-five-iron-laws" aria-label="Permalink to &quot;Superpowers&#39; Five Iron Laws&quot;">​</a></h2><p>Superpowers isn&#39;t just a simple toolset—it forces AI agents to follow five iron laws:</p><table tabindex="0"><thead><tr><th>Iron Law</th><th>Core Content</th><th>Cost of Violation</th></tr></thead><tbody><tr><td><strong>1% Principle</strong></td><td>Even with 1% probability, must invoke a skill</td><td>AI skips necessary checks, leading to missed work</td></tr><tr><td><strong>TDD Iron Law</strong></td><td>No production code without a failing test</td><td>Code becomes untestable, hard to maintain, hides bugs</td></tr><tr><td><strong>Debugging Iron Law</strong></td><td>No fixes without root cause</td><td>Symptom fixes, problem recurrence, wasted time</td></tr><tr><td><strong>Evidence Iron Law</strong></td><td>No completion claims without evidence</td><td>False progress, broken trust, rework</td></tr><tr><td><strong>Review Iron Law</strong></td><td>Early, frequent reviews</td><td>Technical debt accumulation, high rework costs</td></tr></tbody></table><h2 id="_1-skill-invocation-iron-law-preventing-ai-from-cutting-corners" tabindex="-1">1. Skill Invocation Iron Law: Preventing AI from Cutting Corners <a class="header-anchor" href="#_1-skill-invocation-iron-law-preventing-ai-from-cutting-corners" aria-label="Permalink to &quot;1. Skill Invocation Iron Law: Preventing AI from Cutting Corners&quot;">​</a></h2><h3 id="core-principle" tabindex="-1">Core Principle <a class="header-anchor" href="#core-principle" aria-label="Permalink to &quot;Core Principle&quot;">​</a></h3><p><strong>Even with 1% probability, you must invoke a skill.</strong></p><p>AI agents are skilled at &quot;rationalizing&quot;—finding various reasons to skip necessary workflows.</p><h3 id="common-rationalization-excuses-vs-truth" tabindex="-1">Common Rationalization Excuses vs. Truth <a class="header-anchor" href="#common-rationalization-excuses-vs-truth" aria-label="Permalink to &quot;Common Rationalization Excuses vs. Truth&quot;">​</a></h3><table tabindex="0"><thead><tr><th>AI&#39;s Excuse</th><th>Truth</th><th>Countermeasure</th></tr></thead><tbody><tr><td>&quot;This is a simple problem&quot;</td><td>A problem is a task, check skills</td><td>Insist on invoking skills</td></tr><tr><td>&quot;I need more context&quot;</td><td>Skill checks happen before clarifying problems</td><td>Invoke skill first, then ask questions</td></tr><tr><td>&quot;Let me explore the codebase first&quot;</td><td>Skills will tell you how to explore</td><td>Invoke skill first, follow skill&#39;s guidance</td></tr><tr><td>&quot;I can quickly check git/files&quot;</td><td>Files lack conversation context</td><td>Invoke skill first, then read files</td></tr><tr><td>&quot;Let me gather information first&quot;</td><td>Skills will tell you how to gather information</td><td>Invoke skill first, then gather</td></tr><tr><td>&quot;This doesn&#39;t require a formal skill&quot;</td><td>If there&#39;s a skill, use it</td><td>Insist on using it</td></tr><tr><td>&quot;I remember this skill&quot;</td><td>Skills update, read the latest version</td><td>Read the skill every time</td></tr><tr><td>&quot;This doesn&#39;t count as a task&quot;</td><td>Any action is a task</td><td>Insist on invoking skills</td></tr><tr><td>&quot;Using a skill is overkill&quot;</td><td>Simple things will become complex</td><td>Insist on using skills</td></tr><tr><td>&quot;Let me do this one thing first&quot;</td><td>Check before doing anything</td><td>Insist on invoking skills</td></tr><tr><td>&quot;This feels efficient&quot;</td><td>Undisciplined action wastes time</td><td>Skills prevent inefficiency</td></tr><tr><td>&quot;I know what it means&quot;</td><td>Knowing the concept ≠ using the skill</td><td>Must invoke the skill</td></tr></tbody></table><h3 id="skill-priority" tabindex="-1">Skill Priority <a class="header-anchor" href="#skill-priority" aria-label="Permalink to &quot;Skill Priority&quot;">​</a></h3><p>When multiple skills might apply, use this order:</p><ol><li><strong>Process skills first</strong> (brainstorming, debugging) — decide how to handle the task</li><li><strong>Implementation skills second</strong> (TDD, review) — guide execution</li></ol><p>Examples:</p><ul><li>&quot;Build X&quot; → brainstorming first, then implementation skills</li><li>&quot;Fix this bug&quot; → debugging first, then TDD</li></ul><h2 id="_2-tdd-iron-law-reject-post-hoc-testing" tabindex="-1">2. TDD Iron Law: Reject Post-Hoc Testing <a class="header-anchor" href="#_2-tdd-iron-law-reject-post-hoc-testing" aria-label="Permalink to &quot;2. TDD Iron Law: Reject Post-Hoc Testing&quot;">​</a></h2><h3 id="core-principle-1" tabindex="-1">Core Principle <a class="header-anchor" href="#core-principle-1" aria-label="Permalink to &quot;Core Principle&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>NO PRODUCTION CODE WITHOUT A FAILING TEST FIRST</span></span></code></pre></div><p>If you haven&#39;t seen a test fail before writing code, you haven&#39;t proven it tests correctly.</p><h3 id="red-green-refactor-loop" tabindex="-1">RED-GREEN-REFACTOR Loop <a class="header-anchor" href="#red-green-refactor-loop" aria-label="Permalink to &quot;RED-GREEN-REFACTOR Loop&quot;">​</a></h3><div class="language-mermaid vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">mermaid</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">flowchart LR</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    red[RED&lt;br/&gt;Write failing test] --&gt; verify_red{Verify failure}</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    verify_red -- Correct failure --&gt; green[GREEN&lt;br/&gt;Minimal code]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    verify_red -- Wrong failure --&gt; red</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    green --&gt; verify_green{Verify passing}</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    verify_green -- All green --&gt; refactor[REFACTOR&lt;br/&gt;Clean up code]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    verify_green -- Failures --&gt; green</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    refactor --&gt; verify_green</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    verify_green -- All green --&gt; next[Next step]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    next --&gt; red</span></span></code></pre></div><h3 id="common-rationalization-excuses" tabindex="-1">Common Rationalization Excuses <a class="header-anchor" href="#common-rationalization-excuses" aria-label="Permalink to &quot;Common Rationalization Excuses&quot;">​</a></h3><table tabindex="0"><thead><tr><th>AI&#39;s Excuse</th><th>Truth</th></tr></thead><tbody><tr><td>&quot;Too simple, doesn&#39;t need tests&quot;</td><td>Simple code breaks. Tests take 30 seconds.</td></tr><tr><td>&quot;I&#39;ll write tests later&quot;</td><td>Tests passing immediately proves nothing was tested.</td></tr><tr><td>&quot;Post-hoc testing is the same&quot;</td><td>Post-hoc tests answer &quot;what does this do,&quot; tests first answer &quot;what should this do&quot;</td></tr><tr><td>&quot;I manually tested all edge cases&quot;</td><td>Ad-hoc testing ≠ systematic. No record, cannot rerun.</td></tr><tr><td>&quot;Deleting X hours of work is wasteful&quot;</td><td>Sunk cost fallacy. Keeping unverified code is technical debt.</td></tr><tr><td>&quot;Keep as reference, write tests first&quot;</td><td>You&#39;ll tweak it, that&#39;s testing after. Delete means delete.</td></tr><tr><td>&quot;Need to explore first&quot;</td><td>OK. Discard exploration code, start with TDD.</td></tr><tr><td>&quot;Test is hard = design unclear&quot;</td><td>Follow the test. Hard to test = hard to use.</td></tr><tr><td>&quot;TDD slows me down&quot;</td><td>TDD is faster than debugging. Practical = test first.</td></tr><tr><td>&quot;Manual testing is faster&quot;</td><td>Manual doesn&#39;t prove edge cases. Rerun for every change.</td></tr><tr><td>&quot;Existing code has no tests&quot;</td><td>You&#39;re improving it. Add tests to existing code.</td></tr></tbody></table><h3 id="red-flags-stop-immediately" tabindex="-1">Red Flags: Stop Immediately <a class="header-anchor" href="#red-flags-stop-immediately" aria-label="Permalink to &quot;Red Flags: Stop Immediately&quot;">​</a></h3><ul><li>Writing code before tests</li><li>Testing after implementation</li><li>Tests pass immediately</li><li>Cannot explain why tests failed</li><li>&quot;Will add tests later&quot;</li><li>Rationalizing &quot;just this once&quot;</li><li>&quot;I already manually tested&quot;</li><li>&quot;Post-hoc testing is the same&quot; | &quot;It&#39;s about mindset, not ritual&quot; | &quot;Keep as reference&quot; or &quot;adjust existing code&quot; | &quot;Already spent X hours, deleting is wasteful&quot; | &quot;TDD is dogmatic, I&#39;m practical&quot; | &quot;This time is different because...&quot;</li></ul><p><strong>All these mean: delete code, restart with TDD.</strong></p><h2 id="_3-debugging-iron-law-reject-blind-fixes" tabindex="-1">3. Debugging Iron Law: Reject Blind Fixes <a class="header-anchor" href="#_3-debugging-iron-law-reject-blind-fixes" aria-label="Permalink to &quot;3. Debugging Iron Law: Reject Blind Fixes&quot;">​</a></h2><h3 id="core-principle-2" tabindex="-1">Core Principle <a class="header-anchor" href="#core-principle-2" aria-label="Permalink to &quot;Core Principle&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>NO FIXES WITHOUT ROOT CAUSE INVESTIGATION FIRST</span></span></code></pre></div><p>Don&#39;t propose fixes until you&#39;ve completed root cause investigation.</p><h3 id="four-phase-systematic-debugging" tabindex="-1">Four-Phase Systematic Debugging <a class="header-anchor" href="#four-phase-systematic-debugging" aria-label="Permalink to &quot;Four-Phase Systematic Debugging&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Phase</th><th>Core Activity</th><th>Success Criteria</th></tr></thead><tbody><tr><td><strong>1. Root Cause Investigation</strong></td><td>Read error messages, reproduce, check changes, gather evidence</td><td>Understand WHAT and WHY</td></tr><tr><td><strong>2. Pattern Analysis</strong></td><td>Find working examples, compare with references</td><td>Identify differences</td></tr><tr><td><strong>3. Hypothesis Testing</strong></td><td>Form theories, minimal tests</td><td>Confirm or new hypothesis</td></tr><tr><td><strong>4. Implementation</strong></td><td>Create tests, fix, verify</td><td>Bug fixed, tests pass</td></tr></tbody></table><h3 id="common-rationalization-excuses-1" tabindex="-1">Common Rationalization Excuses <a class="header-anchor" href="#common-rationalization-excuses-1" aria-label="Permalink to &quot;Common Rationalization Excuses&quot;">​</a></h3><table tabindex="0"><thead><tr><th>AI&#39;s Excuse</th><th>Truth</th></tr></thead><tbody><tr><td>&quot;Problem is simple, no need for process&quot;</td><td>Simple problems have root causes too. Process is faster for simple bugs.</td></tr><tr><td>&quot;Urgent, no time for process&quot;</td><td>Systematic debugging is faster than guessing and trial-and-error.</td></tr><tr><td>&quot;Try this first, then investigate&quot;</td><td>First fix sets the pattern. Get it right from the start.</td></tr><tr><td>&quot;I&#39;ll write tests to verify the fix&quot;</td><td>Untested fixes aren&#39;t durable. Tests first prove it works.</td></tr><tr><td>&quot;Multiple fixes at once saves time&quot;</td><td>Can&#39;t isolate the effective fix. Introduces new bugs.</td></tr><tr><td>&quot;Reference is too long, I&#39;ll adapt the pattern&quot;</td><td>Partial understanding guarantees bugs. Read completely.</td></tr><tr><td>&quot;I see the problem, let me fix it&quot;</td><td>Seeing symptoms ≠ understanding root cause.</td></tr><tr><td>&quot;Try the fix again&quot; (after 2+ failures)</td><td>3+ failures = architectural problem. Question the pattern, don&#39;t just fix.</td></tr></tbody></table><h3 id="red-flags-stop-immediately-1" tabindex="-1">Red Flags: Stop Immediately <a class="header-anchor" href="#red-flags-stop-immediately-1" aria-label="Permalink to &quot;Red Flags: Stop Immediately&quot;">​</a></h3><ul><li>&quot;Quick fix, investigate later&quot;</li><li>&quot;Try changing X and see if it works&quot;</li><li>&quot;Add multiple changes, run tests&quot;</li><li>&quot;Skip tests, I&#39;ll manually verify&quot; | &quot;Could be X, let me fix it&quot; | &quot;I don&#39;t fully understand but this might work&quot; | &quot;Pattern says X but I&#39;ll adapt differently&quot; | &quot;List main issues: [list fixes, no investigation]&quot; | Propose solutions before tracing data flow | <strong>&quot;Try the fix again&quot;</strong> (already tried 2+ times) | <strong>Each fix reveals new problems in different locations</strong></li></ul><p><strong>All these mean: stop, go back to phase 1.</strong></p><p><strong>If 3+ fixes fail: question the architecture.</strong></p><h2 id="_4-evidence-iron-law-reject-false-completion" tabindex="-1">4. Evidence Iron Law: Reject False Completion <a class="header-anchor" href="#_4-evidence-iron-law-reject-false-completion" aria-label="Permalink to &quot;4. Evidence Iron Law: Reject False Completion&quot;">​</a></h2><h3 id="core-principle-3" tabindex="-1">Core Principle <a class="header-anchor" href="#core-principle-3" aria-label="Permalink to &quot;Core Principle&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>NO COMPLETION CLAIMS WITHOUT FRESH VERIFICATION EVIDENCE</span></span></code></pre></div><p>If this message didn&#39;t run verification commands, you can&#39;t claim it passed.</p><h3 id="gatekeeper-function" tabindex="-1">Gatekeeper Function <a class="header-anchor" href="#gatekeeper-function" aria-label="Permalink to &quot;Gatekeeper Function&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Before claiming any state or expressing satisfaction:</span></span>
<span class="line"><span></span></span>
<span class="line"><span>1. Identify: What command proves this claim?</span></span>
<span class="line"><span>2. Run: Execute the complete command (fresh, complete)</span></span>
<span class="line"><span>3. Read: Full output, check exit code, count failures</span></span>
<span class="line"><span>4. Verify: Does output confirm the claim?</span></span>
<span class="line"><span>   - No: State actual status with evidence</span></span>
<span class="line"><span>   - Yes: State claim with evidence</span></span>
<span class="line"><span>5. Only then: Issue the claim</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Skipping any step = lying, not verification</span></span></code></pre></div><h3 id="common-rationalization-excuses-2" tabindex="-1">Common Rationalization Excuses <a class="header-anchor" href="#common-rationalization-excuses-2" aria-label="Permalink to &quot;Common Rationalization Excuses&quot;">​</a></h3><table tabindex="0"><thead><tr><th>AI&#39;s Excuse</th><th>Truth</th></tr></thead><tbody><tr><td>&quot;Should work now&quot;</td><td>Run verification</td></tr><tr><td>&quot;I&#39;m confident&quot;</td><td>Confidence ≠ evidence</td></tr><tr><td>&quot;Just this once&quot;</td><td>No exceptions</td></tr><tr><td>&quot;Linter passed&quot;</td><td>Linter ≠ compiler</td></tr><tr><td>&quot;Agent said it succeeded&quot;</td><td>Independent verification</td></tr><tr><td>&quot;I&#39;m tired&quot;</td><td>Fatigue is not an excuse</td></tr><tr><td>&quot;Partial check is enough&quot;</td><td>Partial proves nothing</td></tr><tr><td>&quot;Different wording so rule doesn&#39;t apply&quot;</td><td>Spirit over literal</td></tr></tbody></table><h3 id="red-flags-stop-immediately-2" tabindex="-1">Red Flags: Stop Immediately <a class="header-anchor" href="#red-flags-stop-immediately-2" aria-label="Permalink to &quot;Red Flags: Stop Immediately&quot;">​</a></h3><ul><li>Using &quot;should,&quot; &quot;might,&quot; &quot;seems like&quot;</li><li>Expressing satisfaction before verification (&quot;Good!&quot;, &quot;Perfect!&quot;, &quot;Done!&quot;) | Not verifying before commit/push/PR | Trusting agent success reports | Relying on partial verification | Thinking &quot;just this once&quot; | Tired and want work to end | <strong>Any wording suggesting success but not running verification</strong></li></ul><h2 id="_5-code-review-iron-law-early-frequent-reviews" tabindex="-1">5. Code Review Iron Law: Early, Frequent Reviews <a class="header-anchor" href="#_5-code-review-iron-law-early-frequent-reviews" aria-label="Permalink to &quot;5. Code Review Iron Law: Early, Frequent Reviews&quot;">​</a></h2><h3 id="core-principle-4" tabindex="-1">Core Principle <a class="header-anchor" href="#core-principle-4" aria-label="Permalink to &quot;Core Principle&quot;">​</a></h3><p><strong>Review early, review often.</strong></p><h3 id="when-to-request-reviews" tabindex="-1">When to Request Reviews <a class="header-anchor" href="#when-to-request-reviews" aria-label="Permalink to &quot;When to Request Reviews&quot;">​</a></h3><p><strong>Mandatory:</strong></p><ul><li>After every task in subagent-driven development</li><li>After completing major features</li><li>Before merging into main branch</li></ul><p><strong>Optional but valuable:</strong></p><ul><li>When stuck (new perspective)</li><li>Before refactoring (baseline check)</li><li>After fixing complex bugs</li></ul><h3 id="red-flags-never" tabindex="-1">Red Flags: Never <a class="header-anchor" href="#red-flags-never" aria-label="Permalink to &quot;Red Flags: Never&quot;">​</a></h3><ul><li>Skipping reviews because &quot;it&#39;s simple&quot;</li><li>Ignoring serious issues | Continuing with unresolved critical issues | Arguing against valid technical feedback | Trusting agent reports without checking VCS diff</li></ul><h2 id="_6-plan-writing-assume-engineer-has-no-context" tabindex="-1">6. Plan Writing: Assume Engineer Has No Context <a class="header-anchor" href="#_6-plan-writing-assume-engineer-has-no-context" aria-label="Permalink to &quot;6. Plan Writing: Assume Engineer Has No Context&quot;">​</a></h2><h3 id="core-principle-5" tabindex="-1">Core Principle <a class="header-anchor" href="#core-principle-5" aria-label="Permalink to &quot;Core Principle&quot;">​</a></h3><p><strong>Assume engineer has zero context and questionable taste.</strong></p><p>Provide all information they need: which files, code, tests, docs to change for each task, and how to test. Break down the entire plan into bite-sized tasks.</p><h3 id="key-principles" tabindex="-1">Key Principles <a class="header-anchor" href="#key-principles" aria-label="Permalink to &quot;Key Principles&quot;">​</a></h3><ul><li><strong>DRY</strong>: Don&#39;t Repeat Yourself</li><li><strong>YAGNI</strong>: You Aren&#39;t Gonna Need It</li><li><strong>TDD</strong>: Write tests first for every feature</li><li><strong>Frequent commits</strong>: Commit after completing each task</li></ul><h2 id="_7-design-phase-one-question-at-a-time" tabindex="-1">7. Design Phase: One Question at a Time <a class="header-anchor" href="#_7-design-phase-one-question-at-a-time" aria-label="Permalink to &quot;7. Design Phase: One Question at a Time&quot;">​</a></h2><h3 id="core-principle-6" tabindex="-1">Core Principle <a class="header-anchor" href="#core-principle-6" aria-label="Permalink to &quot;Core Principle&quot;">​</a></h3><p><strong>Ask only one question at a time. Don&#39;t overwhelm with multiple questions.</strong></p><h3 id="key-principles-1" tabindex="-1">Key Principles <a class="header-anchor" href="#key-principles-1" aria-label="Permalink to &quot;Key Principles&quot;">​</a></h3><ul><li>Multiple choice is better than open-ended (when possible)</li><li><strong>YAGNI is ruthless</strong>: Remove unnecessary features from all designs</li><li>Explore alternatives: Always present 2-3 approaches before finalizing</li><li>Incremental validation: Present designs in segments, confirm each</li></ul><h2 id="_8-subagent-driven-two-phase-reviews" tabindex="-1">8. Subagent-Driven: Two-Phase Reviews <a class="header-anchor" href="#_8-subagent-driven-two-phase-reviews" aria-label="Permalink to &quot;8. Subagent-Driven: Two-Phase Reviews&quot;">​</a></h2><h3 id="core-principle-7" tabindex="-1">Core Principle <a class="header-anchor" href="#core-principle-7" aria-label="Permalink to &quot;Core Principle&quot;">​</a></h3><p><strong>Every task with fresh subagent + two-phase reviews (specs first, then code quality) = high quality, fast iteration.</strong></p><h3 id="red-flags-never-1" tabindex="-1">Red Flags: Never <a class="header-anchor" href="#red-flags-never-1" aria-label="Permalink to &quot;Red Flags: Never&quot;">​</a></h3><ul><li>Starting implementation on main/master branch without explicit user consent</li><li>Skipping reviews (spec compliance or code quality) | Continuing with unresolved issues | Dispatching multiple implementation subagents concurrently (conflicts) | Letting subagents read plan files (provide full text) | Skipping scenario setup context | Ignoring subagent questions | Starting code quality review before spec compliance ✅ (wrong order) | Moving to next task with any review unresolved</li></ul><h2 id="_9-git-worktree-isolated-development" tabindex="-1">9. Git Worktree: Isolated Development <a class="header-anchor" href="#_9-git-worktree-isolated-development" aria-label="Permalink to &quot;9. Git Worktree: Isolated Development&quot;">​</a></h2><h3 id="core-principle-8" tabindex="-1">Core Principle <a class="header-anchor" href="#core-principle-8" aria-label="Permalink to &quot;Core Principle&quot;">​</a></h3><p><strong>Use Git worktrees to create isolated development environments, keeping the main branch clean.</strong></p><p>Before starting any feature work that needs isolation, create a worktree:</p><ul><li>Don&#39;t pollute the main branch</li><li>Parallel multiple feature branches</li><li>Quickly discard bad experiments</li></ul><h2 id="_10-common-anti-patterns-summary" tabindex="-1">10. Common Anti-Patterns Summary <a class="header-anchor" href="#_10-common-anti-patterns-summary" aria-label="Permalink to &quot;10. Common Anti-Patterns Summary&quot;">​</a></h2><h3 id="_12-rationalization-excuses-ai-agents-will-use" tabindex="-1">12 Rationalization Excuses AI Agents Will Use <a class="header-anchor" href="#_12-rationalization-excuses-ai-agents-will-use" aria-label="Permalink to &quot;12 Rationalization Excuses AI Agents Will Use&quot;">​</a></h3><table tabindex="0"><thead><tr><th>No.</th><th>Excuse Type</th><th>Example</th><th>Response</th></tr></thead><tbody><tr><td>1</td><td><strong>&quot;Simple&quot; excuse</strong></td><td>&quot;This is simple, no skill needed&quot;</td><td>1% principle, must invoke</td></tr><tr><td>2</td><td><strong>&quot;Later&quot; excuse</strong></td><td>&quot;I&#39;ll write tests/investigate later&quot;</td><td>Do it now, later is meaningless</td></tr><tr><td>3</td><td><strong>&quot;Quick fix&quot; excuse</strong></td><td>&quot;Quick fix this, investigate later&quot;</td><td>No fixes without root cause</td></tr><tr><td>4</td><td><strong>&quot;Manual test&quot; excuse</strong></td><td>&quot;I manually tested, it&#39;s fine&quot;</td><td>Manual ≠ automatic, no record</td></tr><tr><td>5</td><td><strong>&quot;Sunk cost&quot; excuse</strong></td><td>&quot;Already spent X hours, deleting is wasteful&quot;</td><td>Sunk cost fallacy, delete and restart</td></tr><tr><td>6</td><td><strong>&quot;Reference&quot; excuse</strong></td><td>&quot;Keep code as reference&quot;</td><td>You&#39;ll tweak it, delete and restart</td></tr><tr><td>7</td><td><strong>&quot;Pragmatic&quot; excuse</strong></td><td>&quot;TDD is dogma, I&#39;m pragmatic&quot;</td><td>Practical = follow the process</td></tr><tr><td>8</td><td><strong>&quot;Explore&quot; excuse</strong></td><td>&quot;Let me explore the code first&quot;</td><td>Skills tell you how to explore</td></tr><tr><td>9</td><td><strong>&quot;Remember&quot; excuse</strong></td><td>&quot;I remember this skill&quot;</td><td>Read the latest version every time</td></tr><tr><td>10</td><td><strong>&quot;Urgent&quot; excuse</strong></td><td>&quot;Urgent, no time for process&quot;</td><td>Process is faster, trial-and-error is slower</td></tr><tr><td>11</td><td><strong>&quot;Partial verification&quot; excuse</strong></td><td>&quot;Linter passed&quot;</td><td>Partial verification proves nothing</td></tr><tr><td>12</td><td><strong>&quot;Fatigue&quot; excuse</strong></td><td>&quot;I&#39;m tired, let&#39;s leave it&quot;</td><td>Fatigue is not an excuse, verify before claiming</td></tr></tbody></table><h3 id="immediate-stop-signals" tabindex="-1">Immediate Stop Signals <a class="header-anchor" href="#immediate-stop-signals" aria-label="Permalink to &quot;Immediate Stop Signals&quot;">​</a></h3><p>When you hear these signals, <strong>stop immediately and return to the correct process</strong>:</p><table tabindex="0"><thead><tr><th>Signal</th><th>Meaning</th><th>Correct Action</th></tr></thead><tbody><tr><td>&quot;Is this?&quot;</td><td>You assumed without verification</td><td>Verify your assumption</td></tr><tr><td>&quot;It will show us...?&quot;</td><td>You should add evidence gathering</td><td>Return to root cause investigation</td></tr><tr><td>&quot;Stop guessing&quot;</td><td>You proposed solutions without understanding</td><td>Complete root cause investigation</td></tr><tr><td>&quot;Think deeply about this problem&quot;</td><td>Question fundamentals, not just symptoms</td><td>Return to the root problem</td></tr><tr><td>&quot;We&#39;re stuck?&quot; (frustrated)</td><td>Your approach isn&#39;t working</td><td>Reanalyze the problem</td></tr></tbody></table><h2 id="_11-golden-rules-for-collaborating-with-ai-agents" tabindex="-1">11. Golden Rules for Collaborating with AI Agents <a class="header-anchor" href="#_11-golden-rules-for-collaborating-with-ai-agents" aria-label="Permalink to &quot;11. Golden Rules for Collaborating with AI Agents&quot;">​</a></h2><h3 id="seven-guidelines-for-building-trust" tabindex="-1">Seven Guidelines for Building Trust <a class="header-anchor" href="#seven-guidelines-for-building-trust" aria-label="Permalink to &quot;Seven Guidelines for Building Trust&quot;">​</a></h3><ol><li><strong>Iron laws are non-negotiable</strong>: TDD, debugging, evidence iron laws are not options</li><li><strong>Evidence over claims</strong>: Don&#39;t trust any completion declarations until you see output</li><li><strong>Recognize rationalization</strong>: AI will find various excuses, must recognize and stop them</li><li><strong>Early reviews</strong>: Review after every task, don&#39;t pile up for PR</li><li><strong>Systematic process</strong>: Don&#39;t skip any steps, even for &quot;simple&quot; tasks</li><li><strong>Respect priorities</strong>: Process skills take precedence over implementation skills</li><li><strong>Trust verification</strong>: Only believe completion when you see command output and evidence</li></ol><h3 id="build-efficient-work-habits" tabindex="-1">Build Efficient Work Habits <a class="header-anchor" href="#build-efficient-work-habits" aria-label="Permalink to &quot;Build Efficient Work Habits&quot;">​</a></h3><div class="tip custom-block"><p class="custom-block-title">Recommended Practice</p><p>At the start of every conversation, you can tell the AI:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Please strictly follow Superpowers skills. Even if you think it&#39;s unnecessary,</span></span>
<span class="line"><span>you must invoke relevant skills first. All &quot;simple,&quot; &quot;quick,&quot; &quot;later&quot;</span></span>
<span class="line"><span>and other rationalization excuses are prohibited.</span></span></code></pre></div><p>This sets expectations, letting the AI agent know you&#39;ll enforce strict discipline.</p></div><h2 id="lesson-summary" tabindex="-1">Lesson Summary <a class="header-anchor" href="#lesson-summary" aria-label="Permalink to &quot;Lesson Summary&quot;">​</a></h2><p>Superpowers&#39; core value isn&#39;t making AI smarter—it&#39;s making AI &quot;obedient&quot;:</p><ul><li><strong>1% Principle</strong> prevents AI from skipping necessary checks</li><li><strong>TDD Iron Law</strong> ensures code is testable and maintainable</li><li><strong>Debugging Iron Law</strong> avoids blind fixes and problem recurrence</li><li><strong>Evidence Iron Law</strong> establishes trust baseline, rejects false progress</li><li><strong>Review Iron Law</strong> finds problems early, reduces late-stage rework</li></ul><p>By recognizing and stopping the 12 common rationalization excuses used by AI agents, you&#39;ll gain:</p><ul><li>Higher code quality</li><li>Faster development speed (less rework)</li><li>More stable delivery (systematic process)</li><li>Better collaboration experience (trust building)</li></ul><h2 id="next-lesson-preview" tabindex="-1">Next Lesson Preview <a class="header-anchor" href="#next-lesson-preview" aria-label="Permalink to &quot;Next Lesson Preview&quot;">​</a></h2><blockquote><p>In the next lesson, we&#39;ll learn <strong><a href="./../../appendix/skills-reference/">Complete Skills Reference</a></strong>.</p><p>You&#39;ll learn:</p><ul><li>Quick reference table for 14 skills</li><li>Trigger conditions and core points for each skill</li><li>How to quickly find the skills you need</li></ul></blockquote><hr><h2 id="appendix-source-code-reference" tabindex="-1">Appendix: Source Code Reference <a class="header-anchor" href="#appendix-source-code-reference" aria-label="Permalink to &quot;Appendix: Source Code Reference&quot;">​</a></h2><details><summary><strong>Click to expand source code locations</strong></summary><blockquote><p>Updated: 2026-02-01</p></blockquote><table tabindex="0"><thead><tr><th>Feature</th><th>File Path</th><th>Line Numbers</th></tr></thead><tbody><tr><td>Skill invocation iron law &amp; 1% principle</td><td><a href="https://github.com/obra/superpowers/blob/main/skills/using-superpowers/SKILL.md#L6-L12" target="_blank" rel="noreferrer"><code>skills/using-superpowers/SKILL.md</code></a></td><td>6-12, 24, 48-66</td></tr><tr><td>TDD iron law &amp; RED-GREEN-REFACTOR</td><td><a href="https://github.com/obra/superpowers/blob/main/skills/test-driven-development/SKILL.md#L31-L45" target="_blank" rel="noreferrer"><code>skills/test-driven-development/SKILL.md</code></a></td><td>31-45, 47-69, 272-289</td></tr><tr><td>Systematic debugging four-phase process</td><td><a href="https://github.com/obra/superpowers/blob/main/skills/systematic-debugging/SKILL.md#L16-L45" target="_blank" rel="noreferrer"><code>skills/systematic-debugging/SKILL.md</code></a></td><td>16-45, 50-122, 215-232</td></tr><tr><td>Evidence-first gatekeeper function</td><td><a href="https://github.com/obra/superpowers/blob/main/skills/verification-before-completion/SKILL.md#L16-L38" target="_blank" rel="noreferrer"><code>skills/verification-before-completion/SKILL.md</code></a></td><td>16-38, 52-62, 64-75</td></tr><tr><td>Code review iron law &amp; Red Flags</td><td>[<code>skills/requesting-code-review/SKILL.md</code>](<a href="https://github.com/obra/superpowers/blob/main/skills/requesting-code-review/SKILL.md#L10-L12" target="_blank" rel="noreferrer">https://github.com/obra/superpowers/blob/main/skills/requesting-code-review/SKILL.md#L10-L12</a>, 92-99)</td><td>10-12, 92-99</td></tr><tr><td>Subagent-driven two-phase reviews</td><td>[<code>skills/subagent-driven-development/SKILL.md</code>](<a href="https://github.com/obra/superpowers/blob/main/skills/subagent-driven-development/SKILL.md#L10-L11" target="_blank" rel="noreferrer">https://github.com/obra/superpowers/blob/main/skills/subagent-driven-development/SKILL.md#L10-L11</a>, 199-214)</td><td>10-11, 199-214</td></tr><tr><td>Plan writing principles (DRY, YAGNI, TDD)</td><td>[<code>skills/writing-plans/SKILL.md</code>](<a href="https://github.com/obra/superpowers/blob/main/skills/writing-plans/SKILL.md#L10-L12" target="_blank" rel="noreferrer">https://github.com/obra/superpowers/blob/main/skills/writing-plans/SKILL.md#L10-L12</a>, 90-96)</td><td>10-12, 90-96</td></tr><tr><td>Design phase principles (one question at a time)</td><td>[<code>skills/brainstorming/SKILL.md</code>](<a href="https://github.com/obra/superpowers/blob/main/skills/brainstorming/SKILL.md#L16-L21" target="_blank" rel="noreferrer">https://github.com/obra/superpowers/blob/main/skills/brainstorming/SKILL.md#L16-L21</a>, 47-54)</td><td>16-21, 47-54</td></tr></tbody></table><p><strong>Key Constants</strong>:</p><ul><li>No hardcoded constants, skill system dynamically loads based on files</li></ul><p><strong>Key Functions</strong>:</p><ul><li>No function definitions, skill system is based on Markdown files and YAML frontmatter</li></ul></details>`,106)])])}const g=e(o,[["render",r]]);export{h as __pageData,g as default};
